<?php defined('ABSPATH') || exit; $license=new FounderKit_License(); $license_data=$license->all(); $is_valid=$license->is_valid(); $remaining_days=$license->get_remaining_days(); ?><div class="fk-admin-wrap"><div class="fk-admin-header"><h1><?php esc_html_e('License Management','founderkit'); ?></h1><p class="fk-tagline"><?php esc_html_e('Activate your FounderKit license to unlock premium features.','founderkit'); ?></p></div><?php if($is_valid): ?><div style="background:#d4edda;border:1px solid #c3e6cb;border-radius:4px;padding:12px;margin-bottom:20px;"><strong><?php esc_html_e('License Active','founderkit'); ?></strong><br><?php echo esc_html__('Status: ','founderkit').esc_html($license_data['status']); ?><br><?php echo esc_html__('Expires: ','founderkit').esc_html($license_data['expiration_date']); ?><?php if($remaining_days>0): ?><br><?php echo esc_html__('Days Remaining: ','founderkit').esc_html($remaining_days); ?><?php endif; ?></div><?php endif; ?><div class="fk-admin-stats" style="margin-bottom:20px;"><div class="fk-stat-card"><span class="fk-stat-label"><?php esc_html_e('Status','founderkit'); ?></span><span class="fk-stat-number" style="font-size:18px;color:<?php echo $is_valid?'#28a745':'#dc3545'; ?>"><?php echo $is_valid?esc_html__('Valid','founderkit'):esc_html__('Invalid','founderkit'); ?></span></div><div class="fk-stat-card"><span class="fk-stat-label"><?php esc_html_e('Expires','founderkit'); ?></span><span class="fk-stat-number" style="font-size:14px;"><?php echo empty($license_data['expiration_date'])?esc_html__('Not Set','founderkit'):esc_html($license_data['expiration_date']); ?></span></div><div class="fk-stat-card"><span class="fk-stat-label"><?php esc_html_e('Domains','founderkit'); ?></span><span class="fk-stat-number" style="font-size:14px;"><?php echo esc_html($license_data['domains_active'].'/'.$license_data['max_domains']); ?></span></div></div><div class="fk-settings-grid" style="grid-template-columns:1fr;"><div class="fk-settings-section"><h2><?php esc_html_e('License Key','founderkit'); ?></h2><form id="fk-license-form"><?php wp_nonce_field('founderkit_license_activate','founderkit_license_nonce'); ?><label class="fk-field"><span><?php esc_html_e('Enter Your License Key','founderkit'); ?></span><input type="text" name="license_key" placeholder="fk_..." value="<?php echo!empty($license_data['license_key'])?esc_attr(substr($license_data['license_key'],0,4).'...'.substr($license_data['license_key'],-4)):''; ?>" style="font-family:monospace;"></label><button type="submit" class="fk-btn fk-btn-primary" style="margin-top:10px;"><?php echo $is_valid?esc_html__('Update License','founderkit'):esc_html__('Activate License','founderkit'); ?></button><?php if($is_valid): ?><button type="button" class="fk-btn fk-btn-outline" id="fk-deactivate-btn" style="margin-top:10px;margin-left:10px;"><?php esc_html_e('Deactivate','founderkit'); ?></button><?php endif; ?><span class="fk-save-msg" style="display:none;margin-left:10px;"></span></form></div><?php if(!empty($license_data['customer_name'])): ?><div class="fk-settings-section"><h2><?php esc_html_e('License Details','founderkit'); ?></h2><div style="font-size:14px;"><strong><?php esc_html_e('Name:','founderkit'); ?></strong> <?php echo esc_html($license_data['customer_name']); ?><br><strong><?php esc_html_e('Email:','founderkit'); ?></strong> <?php echo esc_html($license_data['customer_email']); ?><br><?php if($license_data['last_validation']>0): ?><strong><?php esc_html_e('Last Validated:','founderkit'); ?></strong> <?php echo esc_html(wp_date('Y-m-d H:i:s',$license_data['last_validation'])); ?><br><?php endif; ?><?php if(!empty($license_data['api_validation_error'])): ?><strong style="color:#dc3545;"><?php esc_html_e('Validation Error:','founderkit'); ?></strong> <?php echo esc_html($license_data['api_validation_error']); ?><br><?php endif; ?></div></div><?php endif; ?></div></div>
